package courses

import (
	"context"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

const pageSize = 200

type CoursesService struct {
	queries *db.Queries
}

type CoursesItem struct {
	CourseId string `json:"courseId"`
	Title    string `json:"title"`
}

func NewCoursesService(queries *db.Queries) *CoursesService {
	return &CoursesService{queries: queries}
}

type GetCoursesResult struct {
	Courses []CoursesItem `json:"courses"`
	Cursor  *string       `json:"cursor"`
}

func (service *CoursesService) GetCourses(ctx context.Context, cursor string) (GetCoursesResult, error) {
	var cursorUuid pgtype.UUID

	if cursor != "" {
		cursorUuid.Scan(cursor)
	}

	rawCourses, err := service.queries.GetCourses(ctx, db.GetCoursesParams{Cursor: cursorUuid, Size: pageSize + 1})
	if err != nil {
		return GetCoursesResult{}, err
	}

	slicedRawCourses := rawCourses[0:min(len(rawCourses), pageSize)]

	courses := make([]CoursesItem, len(slicedRawCourses))
	for i, rawCourse := range slicedRawCourses {
		courses[i] = CoursesItem{
			CourseId: rawCourse.CourseID.String(),
			Title:    rawCourse.Title,
		}
	}

	var nextCursor *string
	if len(rawCourses) > pageSize {
		s := rawCourses[pageSize-1].CourseID.String()
		nextCursor = &s
	}

	return GetCoursesResult{
		Courses: courses,
		Cursor:  nextCursor,
	}, nil
}

